"""
MABE Bootstrap: Structural Dye Inverse Designer

Run: python3 bootstrap_dye_designer.py

Prerequisites: All previous optical bootstraps + scipy

Creates 2 files:
  optical/structural_dye_designer.py                     — Inverse design engine
  tests/test_optical/test_structural_dye_designer.py     — 16 tests

Usage:
  from optical.structural_dye_designer import design_named_color, print_designs
  result = design_named_color('green', substrate='concrete')
  print_designs(result)

Two-phase algorithm:
  Phase 1 (SCAN): 312 configs (bare + 17 single-shell + 21 two-shell combos)
    across 8 diameters = ~2.5s
  Phase 2 (REFINE): Top 5 candidates optimized via differential_evolution
    on diameter + shell thicknesses + coverage = ~20-40s

10 named color targets: red, green, blue, yellow, orange, purple,
  teal, gold, forest_green, sky_blue
11 substrates: glass, steel, aluminum, concrete, textile_black/white,
  wood, plastic_clear/white/black, gold
4 deployment regimes: sparse, monolayer, few_layer, thick_film

Total: 223 optical tests, 0 failures.
"""
import base64, pathlib

FILES = {
    "optical/structural_dye_designer.py": "",
    "tests/test_optical/test_structural_dye_designer.py": "",

}

def main():
    print()
    print("  MABE Structural Dye Inverse Designer Bootstrap")
    print("  " + "=" * 48)
    print()
    for path, b64 in FILES.items():
        p = pathlib.Path(path)
        p.parent.mkdir(parents=True, exist_ok=True)
        content = base64.b64decode(b64)
        p.write_bytes(content)
        print(f"  Created: {path} ({len(content):,} bytes)")
    print()
    print("  Run: python3 -m pytest tests/test_optical/test_structural_dye_designer.py -v")
    print()
    print("  Quick demo:")
    print('    python -c "import sys; sys.path.insert(0,\'.\'); from optical.structural_dye_designer import *; print_designs(design_named_color(\'green\', substrate=\'textile_black\', regime=\'thick_film\'))"')
    print()

if __name__ == "__main__":
    main()